const map = global.get('transfers') || {};
// transfers may be a Map-like object or an array of records.
let rows = [];
if (Array.isArray(map)) rows = map.slice();
else if (map && typeof map === 'object') rows = Object.values(map);
rows.sort((a, b) => {
  const ta = new Date((a && (a.created_at || a.updated_at || a.timestamp)) || 0).getTime();
  const tb = new Date((b && (b.created_at || b.updated_at || b.timestamp)) || 0).getTime();
  return tb - ta;
});
msg.headers = { 'Content-Type': 'application/json', 'Cache-Control': 'no-store' };
msg.statusCode = 200;
msg.payload = { transfers: rows, count: rows.length };
return msg;

// AI Insight backend stores outputs in global.ai_insight_outputs (object keyed by output_id).
// Optional file fallback: /data/ai-insight-state/outputs.json (only used if global is empty).
const byId = global.get('ai_insight_outputs') || {};
let rows = [];
if (Array.isArray(byId)) rows = byId.slice();
else if (byId && typeof byId === 'object') rows = Object.values(byId);
rows = rows.map((r) => ({
  output_id:    r.output_id || r.id,
  insight_type: r.insight_type || r.type || null,
  created_at:   r.created_at || r.generated_at || r.timestamp || null,
  user_roles:   r.user_roles || null,
  asset_id:     r.asset_id || r.subject || null,
  agreement_id: r.agreement_id || null,
  hmac:         (r.signed_url || '').split('hmac=')[1] || null,
  bytes:        r.bytes || null
}));
rows.sort((a, b) => new Date(b.created_at || 0).getTime() - new Date(a.created_at || 0).getTime());
msg.headers = { 'Content-Type': 'application/json', 'Cache-Control': 'no-store' };
msg.statusCode = 200;
msg.payload = { insights: rows, count: rows.length };
return msg;
